function wrapText(text: string, columnWidth: number): string {
  const words = text.split(' ');
  const lines: string[] = [];
  let currentLine = '';

  for (const word of words) {
    if (word.length > columnWidth) {
      // Break long word across lines
      if (currentLine) {
        lines.push(currentLine);
        currentLine = '';
      }
      let remaining = word;
      while (remaining.length > columnWidth) {
        lines.push(remaining.slice(0, columnWidth));
        remaining = remaining.slice(columnWidth);
      }
      currentLine = remaining;
    } else if (!currentLine) {
      currentLine = word;
    } else if (currentLine.length + 1 + word.length <= columnWidth) {
      currentLine += ' ' + word;
    } else {
      lines.push(currentLine);
      currentLine = word;
    }
  }
  if (currentLine) lines.push(currentLine);
  return lines.join('\n');
}
